// Deterministic hash: same card ID always gets same flavor text
function hashCode(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash |= 0;
    }
    return Math.abs(hash);
}

export function getFlavorText(cardId: string): FlavorEntry {
    const idx = hashCode(cardId) % FLAVOR_TEXTS.length;
    return FLAVOR_TEXTS[idx];
}

export const FLAVOR_TEXT_COUNT = FLAVOR_TEXTS.length;
